export function parseEntityTagList(value) {
  if (value === undefined || value === null || value === '') {
    return [];
  }
  if (typeof value !== 'string') {
    throw new TypeError('entity-tag list must be a string');
  }

  return value
    .split(',')
    .map((entry) => entry.trim())
    .filter(Boolean);
}

