import { parseEntityTagList } from './entity-tag-list.mjs';

function opaqueRevision(tag) {
  return tag.startsWith('W/') ? tag.slice(2) : tag;
}

function containsRevision(tags, currentTag, ignoreStrength) {
  if (tags.includes('*')) {
    return true;
  }
  if (ignoreStrength) {
    const currentRevision = opaqueRevision(currentTag);
    return tags.some((tag) => opaqueRevision(tag) === currentRevision);
  }
  return tags.includes(currentTag);
}

export function evaluatePreconditions({
  method = 'GET',
  currentTag,
  ifMatch,
  ifNoneMatch
} = {}) {
  if (typeof currentTag !== 'string' || currentTag.length === 0) {
    throw new TypeError('currentTag must be a non-empty string');
  }

  const normalizedMethod = String(method).toUpperCase();
  if (ifMatch !== undefined) {
    const candidates = parseEntityTagList(ifMatch);
    if (!containsRevision(candidates, currentTag, true)) {
      return { status: 412, proceed: false };
    }
  }

  if (ifNoneMatch !== undefined) {
    const candidates = parseEntityTagList(ifNoneMatch);
    if (containsRevision(candidates, currentTag, false)) {
      const status = normalizedMethod === 'GET' || normalizedMethod === 'HEAD'
        ? 304
        : 412;
      return { status, proceed: false };
    }
  }

  return { status: 200, proceed: true };
}

