import { evaluatePreconditions } from './request-preconditions.mjs';

export function serveCatalog(request, representation) {
  const decision = evaluatePreconditions({
    method: request.method,
    currentTag: representation.etag,
    ifMatch: request.headers?.['if-match'],
    ifNoneMatch: request.headers?.['if-none-match']
  });

  return {
    status: decision.status,
    etag: representation.etag,
    body: decision.proceed ? representation.body : null
  };
}

