import test from 'node:test';
import assert from 'node:assert/strict';

import { parseEntityTagList } from '../src/entity-tag-list.mjs';
import { evaluatePreconditions } from '../src/request-preconditions.mjs';
import { serveCatalog } from '../src/catalog-response.mjs';

test('catalog revisions from the original gateway remain readable', () => {
  assert.deepEqual(
    parseEntityTagList('\"catalog-1\", \"catalog-2\"'),
    ['\"catalog-1\"', '\"catalog-2\"']
  );
});

test('a direct catalog hit avoids sending the representation again', () => {
  assert.deepEqual(
    evaluatePreconditions({
      method: 'GET',
      currentTag: '\"catalog-4\"',
      ifNoneMatch: '\"catalog-4\"'
    }),
    { status: 304, proceed: false }
  );
});

test('an ordinary update guard accepts the current revision', () => {
  const response = serveCatalog(
    { method: 'PUT', headers: { 'if-match': '\"catalog-5\"' } },
    { etag: '\"catalog-5\"', body: '{\"enabled\":true}' }
  );

  assert.deepEqual(response, {
    status: 200,
    etag: '\"catalog-5\"',
    body: '{\"enabled\":true}'
  });
});
